INSERT INTO reports (id, status, customer_name, customer_id, blocks) VALUES
('d0000001-0000-0000-0000-000000000001', 'FINALIZADO', 'Maria Aparecida Santos', 'c0000001-0000-0000-0000-000000000001',
 '[{"id":"b0010000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Maria Aparecida Santos","cpf":"111.222.333-44","birthDate":"1985-03-15","age":"40 anos","education":"Ensino Superior Completo","profession":"Professora","motherName":"Helena Santos","fatherName":"Roberto Santos"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0010001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"INTRODUÇÃO","subtitle":"","content":"Paciente do sexo feminino, 40 anos, encaminhada para avaliação psicológica por queixa de ansiedade generalizada com episódios de insônia há aproximadamente 8 meses. Relata piora dos sintomas após mudança de emprego.","labeledItems":[],"useLabeledItems":false}},{"id":"b0010002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"PROCEDIMENTOS REALIZADOS","subtitle":"","content":"Foram realizadas 4 sessões de avaliação, incluindo entrevista clínica semiestruturada, aplicação do Inventário de Ansiedade de Beck (BAI) e Inventário de Depressão de Beck (BDI-II). A paciente apresentou escore de 28 no BAI (ansiedade moderada) e 14 no BDI-II (depressão leve).","labeledItems":[],"useLabeledItems":false}},{"id":"b0010003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"CONCLUSÃO E RECOMENDAÇÕES","subtitle":"","content":"Recomenda-se acompanhamento psicoterapêutico semanal com abordagem cognitivo-comportamental por período mínimo de 12 semanas, com reavaliação ao final do período. Sugere-se também avaliação psiquiátrica para eventual manejo farmacológico da insônia.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000002-0000-0000-0000-000000000002', 'FINALIZADO', 'José Carlos Oliveira', 'c0000002-0000-0000-0000-000000000002',
 '[{"id":"b0020000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"José Carlos Oliveira","cpf":"222.333.444-55","birthDate":"1978-07-22","age":"47 anos","education":"Ensino Superior Completo","profession":"Engenheiro Civil","motherName":"Francisca Oliveira","fatherName":"Antônio Carlos Oliveira"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0020001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"OBJETIVO DA AVALIAÇÃO","subtitle":"Laudo Neuropsicológico","content":"Avaliação neuropsicológica solicitada para investigação de queixas cognitivas relatadas pelo paciente, incluindo dificuldades de memória e concentração no ambiente de trabalho.","labeledItems":[],"useLabeledItems":false}},{"id":"b0020002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"RESULTADOS","subtitle":"","content":"A avaliação das funções executivas demonstra desempenho dentro da faixa esperada para idade e escolaridade. Memória operacional preservada. Atenção sustentada e alternada dentro dos parâmetros normativos. Fluência verbal fonêmica e semântica adequadas.","labeledItems":[],"useLabeledItems":false}},{"id":"b0020003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"CONCLUSÃO","subtitle":"","content":"Não foram identificados déficits cognitivos significativos. As queixas subjetivas podem estar relacionadas a fatores emocionais como estresse ocupacional. Recomenda-se manejo do estresse e reavaliação em 12 meses caso os sintomas persistam.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000003-0000-0000-0000-000000000003', 'EM_REVISAO', 'Fernanda Rodrigues Lima', 'c0000003-0000-0000-0000-000000000003',
 '[{"id":"b0030000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Fernanda Rodrigues Lima","cpf":"333.444.555-66","birthDate":"1992-11-08","age":"33 anos","education":"Ensino Superior Completo","profession":"Designer Gráfica","motherName":"Regina Lima","fatherName":"Carlos Rodrigues Lima"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0030001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"EVOLUÇÃO TERAPÊUTICA","subtitle":"Relatório de Acompanhamento","content":"Paciente em processo psicoterapêutico há 6 meses, com frequência semanal. Diagnóstico inicial de episódio depressivo moderado (F32.1). Abordagem utilizada: Terapia Cognitivo-Comportamental.","labeledItems":[],"useLabeledItems":false}},{"id":"b0030002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"PROGRESSO OBSERVADO","subtitle":"","content":"Evolução positiva nos sintomas de depressão, com redução significativa nos episódios de humor rebaixado. Paciente relata melhora na qualidade do sono, retomada de atividades sociais e maior disposição para atividades laborais. Escore no BDI-II reduziu de 24 (moderado) para 11 (leve).","labeledItems":[],"useLabeledItems":false}},{"id":"b0030003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"PLANO TERAPÊUTICO","subtitle":"","content":"Manter frequência quinzenal nas próximas sessões, com foco na prevenção de recaída e fortalecimento de estratégias de enfrentamento. Previsão de alta terapêutica em aproximadamente 3 meses.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000004-0000-0000-0000-000000000004', 'RASCUNHO', 'Ricardo Alves Barbosa', 'c0000004-0000-0000-0000-000000000004',
 '[{"id":"b0040000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Ricardo Alves Barbosa","cpf":"444.555.666-77","birthDate":"1969-01-30","age":"56 anos","education":"Ensino Médio Completo","profession":"Comerciante","motherName":"Maria José Barbosa","fatherName":"Joaquim Alves Barbosa"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0040001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"MOTIVO DA AVALIAÇÃO","subtitle":"Avaliação Pré-Cirúrgica Bariátrica","content":"Paciente encaminhado para avaliação psicológica pré-cirúrgica conforme protocolo obrigatório para cirurgia bariátrica. IMC atual de 42,3 kg/m².","labeledItems":[],"useLabeledItems":false}},{"id":"b0040002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"AVALIAÇÃO PSICOLÓGICA","subtitle":"","content":"Paciente apresenta motivação adequada e compreensão dos riscos envolvidos no procedimento. Histórico de tentativas anteriores de emagrecimento sem sucesso duradouro. Nega transtornos alimentares (compulsão, bulimia). Rede de apoio familiar presente e engajada no processo.","labeledItems":[],"useLabeledItems":false}},{"id":"b0040003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"PARECER","subtitle":"","content":"Perfil psicológico compatível com o procedimento solicitado. Paciente apto do ponto de vista psicológico para a realização da cirurgia bariátrica, desde que mantenha acompanhamento psicológico no pós-operatório.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000005-0000-0000-0000-000000000005', 'FINALIZADO', 'Patrícia Nunes Costa', 'c0000005-0000-0000-0000-000000000005',
 '[{"id":"b0050000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Patrícia Nunes Costa","cpf":"555.666.777-88","birthDate":"2001-06-12","age":"24 anos","education":"Ensino Médio Completo","profession":"Estudante","motherName":"Sandra Nunes Costa","fatherName":"Paulo Costa"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0050001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"OBJETIVO","subtitle":"Orientação Vocacional","content":"Processo de orientação vocacional realizado em 8 sessões, com objetivo de auxiliar na escolha profissional da paciente, 24 anos, que apresentava indecisão quanto à área de atuação após conclusão do ensino médio.","labeledItems":[],"useLabeledItems":false}},{"id":"b0050002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"INSTRUMENTOS APLICADOS","subtitle":"","content":"Foram aplicados os seguintes instrumentos: Teste de Interesse Profissional (AIP), Questionário de Busca Autodirigida (SDS), Escala de Maturidade para Escolha Profissional (EMEP) e técnicas de colagem e linha da vida. Perfil indica forte inclinação para áreas de saúde e ciências biológicas.","labeledItems":[],"useLabeledItems":false}},{"id":"b0050003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"SUGESTÕES","subtitle":"","content":"Com base nos resultados obtidos e nas reflexões realizadas durante o processo, sugere-se a exploração dos cursos de Biomedicina, Enfermagem ou Fisioterapia. Recomenda-se visitas a universidades e conversas com profissionais dessas áreas.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000006-0000-0000-0000-000000000006', 'FINALIZADO', 'Antônio Marcos Vieira', 'c0000006-0000-0000-0000-000000000006',
 '[{"id":"b0060000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Antônio Marcos Vieira","cpf":"666.777.888-99","birthDate":"1955-09-25","age":"70 anos","education":"Ensino Superior Completo","profession":"Engenheiro Mecânico Aposentado","motherName":"Conceição Vieira","fatherName":"José Marcos Vieira"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0060001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"CONTEXTO","subtitle":"Parecer Psicológico - Aposentadoria","content":"Paciente do sexo masculino, 70 anos, em processo de adaptação à aposentadoria há 6 meses. Encaminhado pela esposa devido a alterações comportamentais observadas desde a cessação das atividades laborais.","labeledItems":[],"useLabeledItems":false}},{"id":"b0060002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"ANÁLISE CLÍNICA","subtitle":"","content":"Identificados sinais de perda de identidade profissional e isolamento social progressivo. Paciente relata sentimento de inutilidade, dificuldade em estabelecer rotina e redução significativa das interações sociais. Apresenta humor rebaixado, porém sem critérios para episódio depressivo maior.","labeledItems":[],"useLabeledItems":false}},{"id":"b0060003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"ENCAMINHAMENTOS","subtitle":"","content":"Encaminhado para grupo terapêutico de transição de carreira e atividades de socialização. Recomenda-se manutenção do acompanhamento individual quinzenal e incentivo à participação em atividades comunitárias e voluntariado.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000007-0000-0000-0000-000000000007', 'EM_REVISAO', 'Claudia Regina Souza', 'c0000007-0000-0000-0000-000000000007',
 '[{"id":"b0070000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Claudia Regina Souza","cpf":"777.888.999-00","birthDate":"1988-12-03","age":"37 anos","education":"Ensino Superior Completo","profession":"Analista de Sistemas","motherName":"Tereza Souza","fatherName":"Marcos Regina Souza"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0070001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"DEMANDA","subtitle":"Avaliação de Estresse Ocupacional","content":"Paciente de 37 anos, analista de sistemas, encaminhada pelo médico do trabalho para avaliação de estresse ocupacional. Relata sintomas há 14 meses com piora progressiva.","labeledItems":[],"useLabeledItems":false}},{"id":"b0070002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"RESULTADOS DA AVALIAÇÃO","subtitle":"","content":"Inventário de Burnout de Maslach (MBI) indica nível severo de esgotamento emocional (escore 38/54), despersonalização moderada (escore 14/30) e baixa realização pessoal (escore 18/48). Paciente relata carga horária de 60+ horas semanais, falta de reconhecimento e conflitos com gestão direta.","labeledItems":[],"useLabeledItems":false}},{"id":"b0070003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"RECOMENDAÇÕES","subtitle":"","content":"Recomendação de afastamento temporário do trabalho por período mínimo de 30 dias e início de psicoterapia intensiva (2x por semana). Sugere-se avaliação psiquiátrica para manejo farmacológico dos sintomas de ansiedade e insônia associados.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000008-0000-0000-0000-000000000008', 'RASCUNHO', 'Eduardo Henrique Dias', 'c0000008-0000-0000-0000-000000000008',
 '[{"id":"b0080000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Eduardo Henrique Dias","cpf":"888.999.000-11","birthDate":"1995-04-18","age":"30 anos","education":"Ensino Superior Completo","profession":"Professor de Educação Física","motherName":"Lúcia Dias","fatherName":"Henrique Eduardo Dias"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0080001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"IDENTIFICAÇÃO DA DEMANDA","subtitle":"Avaliação Infantil","content":"Criança do sexo masculino, 8 anos, cursando o 3º ano do ensino fundamental. Encaminhada pela escola por dificuldades de atenção, inquietude motora e baixo rendimento acadêmico.","labeledItems":[],"useLabeledItems":false}},{"id":"b0080002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"INSTRUMENTOS E PROCEDIMENTOS","subtitle":"","content":"Aplicados: Escala Wechsler de Inteligência para Crianças (WISC-V), Teste de Atenção por Cancelamento (TAC), Escala SNAP-IV (respondida por pais e professora), Teste das Fábulas de Düss e observação lúdica. QI Total: 108 (médio). Índice de Memória Operacional: 89 (médio inferior). Velocidade de processamento: 92 (médio).","labeledItems":[],"useLabeledItems":false}},{"id":"b0080003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"HIPÓTESE DIAGNÓSTICA","subtitle":"","content":"Hipótese diagnóstica de TDAH tipo predominantemente desatento (F90.0). Sugerida avaliação neuropediátrica complementar para confirmação diagnóstica e eventual intervenção medicamentosa. Recomenda-se também psicopedagogia e orientação à escola.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000009-0000-0000-0000-000000000009', 'FINALIZADO', 'Luciana Ferreira Melo', 'c0000009-0000-0000-0000-000000000009',
 '[{"id":"b0090000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Luciana Ferreira Melo","cpf":"999.000.111-22","birthDate":"1973-08-07","age":"52 anos","education":"Ensino Superior Completo","profession":"Advogada","motherName":"Aparecida Melo","fatherName":"Jorge Ferreira Melo"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0090001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"DADOS DO PROCESSO","subtitle":"Laudo Pericial - Vara de Família","content":"Avaliação pericial solicitada pelo juízo da 3ª Vara de Família da Comarca de Fortaleza, nos autos do processo nº 0000123-45.2025.8.06.0001. Realizadas entrevistas individuais com ambos os genitores e sessões de observação da interação parental com a criança.","labeledItems":[],"useLabeledItems":false}},{"id":"b0090002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"ANÁLISE PERICIAL","subtitle":"","content":"Ambos os genitores demonstram vínculo afetivo adequado com a criança e capacidade parental preservada. Não foram identificados indicadores de negligência, abuso ou alienação parental. A criança apresenta desenvolvimento socioemocional compatível com a idade e manifesta desejo de convivência com ambos os pais.","labeledItems":[],"useLabeledItems":false}},{"id":"b0090003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"PARECER TÉCNICO","subtitle":"","content":"Com base na avaliação realizada, este parecer técnico indica que a guarda compartilhada com residência alternada atende ao melhor interesse da criança, desde que os genitores mantenham comunicação respeitosa e colaborativa nas decisões relativas à educação e saúde do menor.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000010-0000-0000-0000-000000000010', 'FINALIZADO', 'Marcos Paulo Araújo', 'c0000010-0000-0000-0000-000000000010',
 '[{"id":"b0100000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Marcos Paulo Araújo","cpf":"000.111.222-33","birthDate":"1982-02-14","age":"43 anos","education":"Ensino Técnico Completo","profession":"Eletricista","motherName":"Vera Lúcia Araújo","fatherName":"Paulo Marcos Araújo"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0100001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"CONTEXTO INSTITUCIONAL","subtitle":"Avaliação Psicossocial","content":"Avaliação realizada no contexto de admissão em programa de assistência social do CRAS Regional Leste. Paciente do sexo masculino, 43 anos, desempregado há 8 meses, com família composta por esposa e 3 filhos menores.","labeledItems":[],"useLabeledItems":false}},{"id":"b0100002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"AVALIAÇÃO","subtitle":"","content":"Paciente apresenta vulnerabilidade socioeconômica significativa e rede de apoio fragilizada. Relata sintomas de ansiedade e insônia relacionados à situação financeira. Possui formação técnica em eletricidade, mas encontra dificuldades de reinserção no mercado formal. Vínculo familiar preservado, com relação conjugal estável.","labeledItems":[],"useLabeledItems":false}},{"id":"b0100003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"INDICAÇÕES","subtitle":"","content":"Indicado acompanhamento psicossocial continuado com frequência quinzenal. Inserção em programa de geração de renda e capacitação profissional. Encaminhamento dos filhos para atividades socioeducativas no contraturno escolar. Monitoramento da saúde mental do paciente com possível encaminhamento para CAPS caso necessário.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000011-0000-0000-0000-000000000011', 'RASCUNHO', 'Renata Cristina Barros', 'c0000011-0000-0000-0000-000000000011',
 '[{"id":"b0110000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Renata Cristina Barros","cpf":"111.333.555-77","birthDate":"1998-10-20","age":"27 anos","education":"Ensino Superior Incompleto","profession":"Estudante de Nutrição","motherName":"Cláudia Barros","fatherName":"Ricardo Cristina Barros"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0110001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"QUEIXA PRINCIPAL","subtitle":"Avaliação de Transtorno Alimentar","content":"Paciente do sexo feminino, 27 anos, procurou atendimento por comportamentos restritivos alimentares e insatisfação com a imagem corporal. Relata perda de 15kg nos últimos 6 meses através de restrição calórica severa.","labeledItems":[],"useLabeledItems":false}},{"id":"b0110002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"AVALIAÇÃO CLÍNICA","subtitle":"","content":"Pontuação elevada no EAT-26 (escore 31, ponto de corte 21). Distorção significativa da imagem corporal identificada através da Escala de Silhuetas de Stunkard. Paciente com IMC atual de 18,2 (abaixo do peso). Relata contagem obsessiva de calorias, evitação de refeições sociais e exercício físico compulsivo.","labeledItems":[],"useLabeledItems":false}},{"id":"b0110003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"ENCAMINHAMENTOS","subtitle":"","content":"Encaminhamento para equipe multidisciplinar composta por nutricionista especializada em transtornos alimentares e psiquiatra. Início de psicoterapia com foco em reestruturação cognitiva da imagem corporal e normalização dos padrões alimentares.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000012-0000-0000-0000-000000000012', 'EM_REVISAO', 'Thiago Nascimento Pinto', 'c0000012-0000-0000-0000-000000000012',
 '[{"id":"b0120000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Thiago Nascimento Pinto","cpf":"222.444.666-88","birthDate":"1965-05-01","age":"60 anos","education":"Ensino Médio Completo","profession":"Motorista Aposentado","motherName":"Josefa Pinto","fatherName":"Sebastião Nascimento Pinto"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0120001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"HISTÓRICO","subtitle":"Relatório de Acompanhamento - Dependência Química","content":"Paciente do sexo masculino, 60 anos, em tratamento ambulatorial para uso problemático de álcool desde janeiro de 2025. Histórico de consumo abusivo por 25 anos com duas internações anteriores. Iniciou programa de tratamento integrado em setembro de 2024.","labeledItems":[],"useLabeledItems":false}},{"id":"b0120002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"EVOLUÇÃO DO TRATAMENTO","subtitle":"","content":"Paciente completou 90 dias de abstinência contínua com suporte do grupo terapêutico semanal. Participação ativa nas sessões individuais e em grupo. Restabelecimento progressivo dos vínculos familiares. Retomou atividades laborais em regime parcial. AUDIT atual: 4 pontos (zona I - uso de baixo risco), comparado a 28 pontos no início do tratamento.","labeledItems":[],"useLabeledItems":false}},{"id":"b0120003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"PLANO DE CONTINUIDADE","subtitle":"","content":"Manter acompanhamento psicoterapêutico individual semanal e participação no grupo de prevenção de recaída. Próxima avaliação clínica em 30 dias. Objetivo de longo prazo: manutenção da abstinência e consolidação da rede de suporte social.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000013-0000-0000-0000-000000000013', 'FINALIZADO', 'Vanessa Teixeira Ramos', 'c0000013-0000-0000-0000-000000000013',
 '[{"id":"b0130000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Vanessa Teixeira Ramos","cpf":"333.555.777-99","birthDate":"1990-07-16","age":"35 anos","education":"Ensino Superior Completo","profession":"Assistente Social","motherName":"Marlene Ramos","fatherName":"Valdir Teixeira Ramos"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0130001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"OBJETIVO DA AVALIAÇÃO","subtitle":"Parecer Psicológico para Habilitação à Adoção","content":"Avaliação psicológica do casal Vanessa Teixeira Ramos e Rafael Ramos Silva para fins de habilitação à adoção, conforme determinação do juízo da Vara da Infância e Juventude da Comarca de Florianópolis.","labeledItems":[],"useLabeledItems":false}},{"id":"b0130002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"AVALIAÇÃO DO CASAL","subtitle":"","content":"O casal demonstra estabilidade emocional, relacionamento conjugal saudável e motivação genuína para a parentalidade adotiva. Ambos apresentam compreensão adequada do processo adaptativo, das possíveis dificuldades e da importância do respeito à história pregressa da criança. Possuem rede de apoio familiar ampla e condições socioeconômicas adequadas.","labeledItems":[],"useLabeledItems":false}},{"id":"b0130003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"PARECER","subtitle":"","content":"Parecer FAVORÁVEL à habilitação do casal para adoção. Recomenda-se a participação no grupo de preparação para adotantes oferecido pela Vara da Infância e Juventude, bem como acompanhamento psicológico pós-adoção durante o período de adaptação.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000014-0000-0000-0000-000000000014', 'RASCUNHO', 'Wellington Silva Moura', 'c0000014-0000-0000-0000-000000000014',
 '[{"id":"b0140000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Wellington Silva Moura","cpf":"444.666.888-00","birthDate":"1977-11-29","age":"48 anos","education":"Ensino Superior Completo","profession":"Policial Civil Aposentado","motherName":"Ivone Moura","fatherName":"José Silva Moura"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0140001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"DADOS DA AVALIAÇÃO","subtitle":"Avaliação Psicológica para Porte de Arma de Fogo","content":"Avaliação psicológica realizada conforme Instrução Normativa nº 78/2014 da Polícia Federal e Resolução CFP nº 018/2008. Paciente do sexo masculino, 48 anos, policial civil aposentado, solicitando renovação do porte de arma de fogo.","labeledItems":[],"useLabeledItems":false}},{"id":"b0140002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"TESTES APLICADOS","subtitle":"","content":"Bateria de testes composta por: Palográfico (personalidade), Teste de Atenção Concentrada (AC), Teste de Memória Visual de Rostos (MVR) e Teste Não Verbal de Inteligência (R1). Todos os resultados encontram-se dentro dos parâmetros esperados para a função. Não foram identificados indicadores de agressividade descontrolada, impulsividade patológica ou comprometimento cognitivo.","labeledItems":[],"useLabeledItems":false}},{"id":"b0140003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"RESULTADO","subtitle":"","content":"Resultado: APTO para manuseio de arma de fogo. O avaliado apresenta condições psicológicas adequadas, com controle emocional preservado, capacidade atencional e mnemônica dentro da normalidade, e traços de personalidade compatíveis com a responsabilidade do porte de arma.","labeledItems":[],"useLabeledItems":false}}]'),

('d0000015-0000-0000-0000-000000000015', 'FINALIZADO', 'Adriana Campos Lopes', 'c0000015-0000-0000-0000-000000000015',
 '[{"id":"b0150000-0000-0000-0000-000000000001","type":"identification","order":0,"collapsed":false,"data":{"professional":{"name":"Dra. Ana Silva","crp":"06/12345","specialization":"Psicologia Clínica"},"customer":{"name":"Adriana Campos Lopes","cpf":"555.777.999-11","birthDate":"2003-01-09","age":"22 anos","education":"Ensino Superior Incompleto","profession":"Estudante de Psicologia","motherName":"Beatriz Lopes","fatherName":"Fernando Campos Lopes"},"date":"2025-12-15","location":"São Paulo - SP"}},{"id":"b0150001-0000-0000-0000-000000000001","type":"text","order":1,"collapsed":false,"data":{"title":"HISTÓRICO DO ATENDIMENTO","subtitle":"Relatório de Alta Terapêutica","content":"Paciente do sexo feminino, 22 anos, iniciou processo psicoterapêutico em setembro de 2024 com queixa principal de ansiedade social severa que impactava significativamente sua vida acadêmica e social. Frequência inicial semanal, totalizando 72 sessões ao longo de 18 meses.","labeledItems":[],"useLabeledItems":false}},{"id":"b0150002-0000-0000-0000-000000000001","type":"text","order":2,"collapsed":false,"data":{"title":"EVOLUÇÃO E RESULTADOS","subtitle":"","content":"Objetivos terapêuticos alcançados com remissão completa dos sintomas de ansiedade social. Paciente conseguiu retomar apresentações acadêmicas, participar de eventos sociais e iniciar estágio profissional. Escore na Escala de Ansiedade Social de Liebowitz reduziu de 82 (ansiedade social severa) para 24 (ansiedade social não significativa). Manutenção dos ganhos terapêuticos por período superior a 3 meses.","labeledItems":[],"useLabeledItems":false}},{"id":"b0150003-0000-0000-0000-000000000001","type":"text","order":3,"collapsed":false,"data":{"title":"ALTA","subtitle":"","content":"Alta terapêutica consensual, acordada entre terapeuta e paciente, com base na estabilidade dos resultados obtidos. Orientação para retorno caso haja recorrência dos sintomas ou surgimento de novas demandas. Portas abertas para retomada do processo a qualquer momento.","labeledItems":[],"useLabeledItems":false}}]');

